import{_ as o,o as a,c as u,a4 as q}from"./chunks/framework.ChErgFjV.js";const p=JSON.parse('{"title":"《置身事内》读书笔记","description":"","frontmatter":{"title":"《置身事内》读书笔记","date":"2026-07-11T00:00:00.000Z","tags":["读书笔记","政治经济学","中国经济","地方政府","土地财政"]},"headers":[],"relativePath":"study/reading-notes/20260711-《置身事内》读书笔记.md","filePath":"study/reading-notes/20260711-《置身事内》读书笔记.md","lastUpdated":1783749868000}'),e={name:"study/reading-notes/20260711-《置身事内》读书笔记.md"};function l(r,t,i,d,h,n){return a(),u("div",null,[...t[0]||(t[0]=[q('<h1 id="《置身事内-中国政府与经济发展》读书笔记" tabindex="-1">《置身事内：中国政府与经济发展》读书笔记 <a class="header-anchor" href="#《置身事内-中国政府与经济发展》读书笔记" aria-label="Permalink to &quot;《置身事内：中国政府与经济发展》读书笔记&quot;">​</a></h1><blockquote><p>作者：兰小欢 | 出版：上海人民出版社，2021年 阅读时间：2026-07-11</p></blockquote><hr><h2 id="📌-一、核心观点" tabindex="-1">📌 一、核心观点 <a class="header-anchor" href="#📌-一、核心观点" aria-label="Permalink to &quot;📌 一、核心观点&quot;">​</a></h2><h3 id="本书讲了什么" tabindex="-1">本书讲了什么 <a class="header-anchor" href="#本书讲了什么" aria-label="Permalink to &quot;本书讲了什么&quot;">​</a></h3><p>本书以中国地方政府投融资为主线，解释政府如何深度参与经济发展。上篇讲微观机制（地方权力与事务、财税体制、土地金融、产业政策），下篇讲宏观现象（城市化与房价、债务风险、国内国际失衡），核心论点：<strong>在中国，政府不但影响&quot;蛋糕&quot;的分配，也参与&quot;蛋糕&quot;的生产，脱离政府谈经济是不可能的。</strong></p><h3 id="核心论点-5个" tabindex="-1">核心论点（5个） <a class="header-anchor" href="#核心论点-5个" aria-label="Permalink to &quot;核心论点（5个）&quot;">​</a></h3><ol><li><p><strong>分税制是理解中国经济的钥匙</strong>：1994年分税制改革后，中央拿走大部分税收，地方政府被迫另谋出路，催生了&quot;土地财政&quot;和&quot;土地金融&quot;，彻底改变了地方政府发展经济的方式。</p></li><li><p><strong>&quot;土地财政+土地金融&quot;是一套完整的资本化体系</strong>：地方政府低价供应工业用地招商引资，高价供应商住用地获取卖地收入，再将未来土地收益资本化从银行借入天量资金，推动快速工业化和城市化，但也积累了巨额债务。</p></li><li><p><strong>地方政府竞争是经济增长的核心引擎</strong>：以行政区划为单位、以税收和土地为手段的招商引资竞争，加上&quot;官场+市场&quot;的双重激励体制，推动各地拼命发展经济。</p></li><li><p><strong>发展模式已到转型拐点</strong>：重投资轻消费导致内需不足、产能过剩、债务高企、贫富分化，&quot;生产型政府&quot;必须向&quot;服务型政府&quot;转型。</p></li><li><p><strong>发展过程与发展目标不同</strong>：不能简单套用发达国家的理论来评判发展中国家，也不能用过去的成功经验来指导未来，必须实事求是、具体问题具体分析。</p></li></ol><h3 id="关键框架-模型" tabindex="-1">关键框架/模型 <a class="header-anchor" href="#关键框架-模型" aria-label="Permalink to &quot;关键框架/模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>机制</th><th>成就</th><th>代价</th></tr></thead><tbody><tr><td>1985-1993 财政包干</td><td>地方截留税收→乡镇企业兴起</td><td>乡镇经济活跃</td><td>中央财政枯竭、两比重下降</td></tr><tr><td>1994-2001 分税制</td><td>中央拿走增值税75%→宏观调控能力大增</td><td>亚洲金融危机平稳度过</td><td>地方财政吃紧</td></tr><tr><td>2001-2015 土地财政+金融</td><td>卖地收入+城投公司借债→城市化工业化加速</td><td>GDP飞速增长、基础设施完善</td><td>房价飞涨、地方债高企、贫富分化</td></tr><tr><td>2015至今 转型调整</td><td>债务置换+供给侧改革+要素市场化</td><td>去杠杆、产业结构优化</td><td>增速放缓、改革阵痛</td></tr></tbody></table><hr><h2 id="💡-二、启发思考" tabindex="-1">💡 二、启发思考 <a class="header-anchor" href="#💡-二、启发思考" aria-label="Permalink to &quot;💡 二、启发思考&quot;">​</a></h2><h3 id="对一般人的启发" tabindex="-1">对一般人的启发 <a class="header-anchor" href="#对一般人的启发" aria-label="Permalink to &quot;对一般人的启发&quot;">​</a></h3><ol><li><p><strong>政策不是凭空而来</strong>：每项重大政策背后都有激烈的央地博弈，如分税制谈判中朱镕基亲自跑十几个省、与广东的激烈交锋，&quot;成功的政策背后是成功的协商和妥协&quot;。</p></li><li><p><strong>房价问题根源在土地制度</strong>：建设用地指标不能跨省交易，土地流向与人口流向背道而驰——人往东部走，地往西部供，房价差距越拉越大。</p></li><li><p><strong>中国不会爆发美式金融危机</strong>：首付比例高（30%）、按揭没有层层衍生品、资本账户管制，这三个防火墙让系统性崩溃的概率很低。</p></li><li><p><strong>消费不足不是文化问题</strong>：高储蓄率背后是计划生育、民生支出不足、房价上涨三者共同作用——不是&quot;中国人天生爱存钱&quot;。</p></li><li><p><strong>贸易冲突的根源在国内结构</strong>：国内消费不足→产能过剩→对外输出→贸易失衡→贸易战，&quot;对外贸易失衡也是内部结构失衡的延续&quot;。</p></li></ol><h3 id="对我的启发-🎯" tabindex="-1">对我的启发 🎯 <a class="header-anchor" href="#对我的启发-🎯" aria-label="Permalink to &quot;对我的启发 🎯&quot;">​</a></h3><ol><li><p><strong>理解&quot;制度红利&quot;比追风口更重要</strong>：过去20年中国互联网和房地产的繁荣，底层是土地金融和城投模式提供的廉价资本与基础设施，而非单纯的技术革命。判断未来趋势，要看制度怎么变。</p></li><li><p><strong>地方政府的&quot;招商引资&quot;思维可以迁移到技术管理</strong>：地方政府像运营商场一样运营城市——低价引入核心商铺（大企业），靠分成（税收）和配套服务（商住地价）盈利。技术团队搭建也可以用这种&quot;生态运营&quot;思维。</p></li><li><p><strong>转型焦虑是系统性的，不是个人的</strong>：作为17年技术管理者，我的焦虑（行业天花板、身体精力下降）与整个经济从&quot;生产型&quot;向&quot;服务型&quot;转型的结构阵痛同步，理解大趋势才能找准小定位。</p></li><li><p><strong>AI编程推广的深层背景</strong>：我正在推广AI编程工具，本质上是在帮助企业用技术手段替代人力成本——这恰好是本书所说的&quot;资本替代劳动&quot;趋势的微观体现，但要注意这个方向可能加剧收入分配问题。</p></li><li><p><strong>&quot;比较优势&quot;可以被创造</strong>：韩国1970年代从纺织业跳到重工业，中国从组装代工跳到面板、光伏——对个人来说，你的&quot;比较优势&quot;也不是静态的，可以通过有策略的学习和转型来重塑。</p></li></ol><hr><h2 id="🎯-三、以我的背景给的建议" tabindex="-1">🎯 三、以我的背景给的建议 <a class="header-anchor" href="#🎯-三、以我的背景给的建议" aria-label="Permalink to &quot;🎯 三、以我的背景给的建议&quot;">​</a></h2><h3 id="建议一-从-做蛋糕-转向-分蛋糕-赛道-🔴🔴🔴" tabindex="-1">建议一：从&quot;做蛋糕&quot;转向&quot;分蛋糕&quot;赛道 🔴🔴🔴 <a class="header-anchor" href="#建议一-从-做蛋糕-转向-分蛋糕-赛道-🔴🔴🔴" aria-label="Permalink to &quot;建议一：从&quot;做蛋糕&quot;转向&quot;分蛋糕&quot;赛道 🔴🔴🔴&quot;">​</a></h3><p>中国正从&quot;生产型政府&quot;向&quot;服务型政府&quot;转型，从重投资到重民生，从重企业到重居民。对应到职业选择：与其继续在&quot;做蛋糕&quot;端（企业降本增效工具），不如转向&quot;分蛋糕&quot;端（教育、培训、咨询等民生服务）。备考教师资格证就是这个方向的正确起步。</p><h3 id="建议二-深耕-政企关系理解力-这个独特优势-🔴🔴🔴" tabindex="-1">建议二：深耕&quot;政企关系理解力&quot;这个独特优势 🔴🔴🔴 <a class="header-anchor" href="#建议二-深耕-政企关系理解力-这个独特优势-🔴🔴🔴" aria-label="Permalink to &quot;建议二：深耕&quot;政企关系理解力&quot;这个独特优势 🔴🔴🔴&quot;">​</a></h3><p>17年技术管理经验+本书的政经框架，构成了一种稀缺能力——既懂技术又懂政策逻辑。很多技术人只会看技术趋势，看不懂政策文件中的机会。这种&quot;双语能力&quot;在产业咨询、政府数字化、科技政策研究等领域极为值钱。</p><h3 id="建议三-理解-土地财政退场-的连锁效应-🔴🔴" tabindex="-1">建议三：理解&quot;土地财政退场&quot;的连锁效应 🔴🔴 <a class="header-anchor" href="#建议三-理解-土地财政退场-的连锁效应-🔴🔴" aria-label="Permalink to &quot;建议三：理解&quot;土地财政退场&quot;的连锁效应 🔴🔴&quot;">​</a></h3><p>土地财政和土地金融是过去20年一切繁荣的底层逻辑，它退场意味着：地方政府收入结构变化→招商引资模式变化→产业政策方向变化→城市兴衰格局变化。你的职业和投资决策都应该基于&quot;后土地财政时代&quot;的逻辑，而非过去20年的惯性。</p><h3 id="建议四-用-地方竞争-视角选择城市和发展方向-🔴🔴" tabindex="-1">建议四：用&quot;地方竞争&quot;视角选择城市和发展方向 🔴🔴 <a class="header-anchor" href="#建议四-用-地方竞争-视角选择城市和发展方向-🔴🔴" aria-label="Permalink to &quot;建议四：用&quot;地方竞争&quot;视角选择城市和发展方向 🔴🔴&quot;">​</a></h3><p>不是所有城市都在同步转型。合肥押注京东方成功转型高科技，而很多中西部城市仍在旧模式中挣扎。选择城市就是选择你嵌入哪个发展模式。广州作为一线城市+省会，既有土地财政惯性也有转型压力，教师资格在这里的&quot;含金量&quot;高于普通二三线。</p><h3 id="建议五-给孩子灌输-制度思维-而非-技能焦虑-🟡" tabindex="-1">建议五：给孩子灌输&quot;制度思维&quot;而非&quot;技能焦虑&quot; 🟡 <a class="header-anchor" href="#建议五-给孩子灌输-制度思维-而非-技能焦虑-🟡" aria-label="Permalink to &quot;建议五：给孩子灌输&quot;制度思维&quot;而非&quot;技能焦虑&quot; 🟡&quot;">​</a></h3><p>两个孩子的教育，与其只盯着分数和技能，不如帮他们建立&quot;制度思维&quot;——理解规则如何制定、利益如何分配、政策如何影响个人。这种思维框架比任何单项技能都更能抵御时代变化。</p><h3 id="建议六-ai编程推广中嵌入-人的价值-叙事-🟡" tabindex="-1">建议六：AI编程推广中嵌入&quot;人的价值&quot;叙事 🟡 <a class="header-anchor" href="#建议六-ai编程推广中嵌入-人的价值-叙事-🟡" aria-label="Permalink to &quot;建议六：AI编程推广中嵌入&quot;人的价值&quot;叙事 🟡&quot;">​</a></h3><p>如果AI编程只是帮企业省人，那你就站在了&quot;资本替代劳动&quot;的一边，长期看会加剧结构性矛盾。更可持续的叙事是：AI让程序员从&quot;编码工&quot;变成&quot;问题解决者&quot;，释放出更多时间去理解业务、理解用户、理解政策——这恰恰是&quot;服务型&quot;转型所需要的。</p><hr><h2 id="📋-四、行动计划" tabindex="-1">📋 四、行动计划 <a class="header-anchor" href="#📋-四、行动计划" aria-label="Permalink to &quot;📋 四、行动计划&quot;">​</a></h2><h3 id="短期-1-3个月" tabindex="-1">短期（1-3个月） <a class="header-anchor" href="#短期-1-3个月" aria-label="Permalink to &quot;短期（1-3个月）&quot;">​</a></h3><ul><li>[ ] 用本书的&quot;央地博弈&quot;框架分析当前广州教育政策动向，为教师资格备考增加政策理解维度</li><li>[ ] 在AI编程培训中增加一节&quot;理解政策环境&quot;，帮助团队成员建立政经视野</li><li>[ ] 整理本书关键数据（分税制前后对比、土地财政规模、居民债务占比等）制作一页纸速查卡</li></ul><h3 id="中期-3-6个月" tabindex="-1">中期（3-6个月） <a class="header-anchor" href="#中期-3-6个月" aria-label="Permalink to &quot;中期（3-6个月）&quot;">​</a></h3><ul><li>[ ] 系统学习&quot;后土地财政时代&quot;的城市发展趋势，评估广州在教育、科技服务领域的增长空间</li><li>[ ] 完成教师资格考试后，研究教育行业中的&quot;政企合作&quot;机会（如校企合作、职业培训等）</li><li>[ ] 用本书的&quot;地方竞争&quot;框架，写一篇分析中国各城市AI产业政策差异的内部报告</li></ul><h3 id="长期-6-24个月" tabindex="-1">长期（6-24个月） <a class="header-anchor" href="#长期-6-24个月" aria-label="Permalink to &quot;长期（6-24个月）&quot;">​</a></h3><ul><li>[ ] 构建从&quot;技术管理&quot;到&quot;产业咨询/政策研究&quot;的转型路径，核心卖点是&quot;技术+政经双视角&quot;</li><li>[ ] 探索在教育领域创业的可能——结合AI编程推广经验和政策理解力，做&quot;技术素养+制度素养&quot;双轨教育</li><li>[ ] 持续跟踪房产税、土地改革、要素市场化等关键政策进展，每季度做一次个人影响评估</li></ul><hr><h2 id="📖-精彩摘录" tabindex="-1">📖 精彩摘录 <a class="header-anchor" href="#📖-精彩摘录" aria-label="Permalink to &quot;📖 精彩摘录&quot;">​</a></h2><blockquote><p>&quot;在我国，政府不但影响&#39;蛋糕&#39;的分配，也参与&#39;蛋糕&#39;的生产，所以我们不可能脱离政府谈经济。&quot;</p></blockquote><blockquote><p>&quot;成功的政策背后是成功的协商和妥协，而不是机械的命令与执行。&quot;</p></blockquote><blockquote><p>&quot;所谓&#39;土地财政&#39;的实质是&#39;房地产财政&#39;。&quot;</p></blockquote><blockquote><p>&quot;土地的资本化，实质是个人收入的资本化。支撑房价和地价的，是人的收入。忽略了人，城市化就入了歧途。&quot;</p></blockquote><blockquote><p>&quot;&#39;比较优势&#39;具有很大的不确定性，是可以靠人为创造的。而对于没干过的事情，事前其实无从准确判断机会成本，没干过怎么知道呢？&quot;</p></blockquote><blockquote><p>&quot;行政手段造成的扭曲往往只有行政力量才能破解。&quot;</p></blockquote><blockquote><p>&quot;现实世界没有定义，只有现象，只有环环相扣的权责关系。&quot;</p></blockquote><blockquote><p>&quot;&#39;有为政府&#39;和&#39;有效市场&#39;一样，都不是天然就存在的，需要不断建设和完善。&quot;</p></blockquote><blockquote><p>&quot;在成功的经济体中，经济政策一定是务实的，不是意识形态化的。是具体的，不是抽象的。&quot;</p></blockquote><blockquote><p>&quot;生活过得好一点，比大多数宏伟更宏伟。&quot;</p></blockquote>',50)])])}const c=o(e,[["render",l]]);export{p as __pageData,c as default};
